package main

import (
	"errors"
	"fmt"
	"testing"
)

func divide(a, b float64) (float64, error) {
	if b == 0 {
		return 0, errors.New("cannot divide by zero")
	}
	return a / b, nil
}

func runTest(a, b float64, t *testing.T) {
	result, err := divide(a, b)
	if err != nil {
		t.Fatalf("divide(%v, %v) returned error: %v", a, b, err)
	}
	if result != a/b {
		t.Errorf("divide(%v, %v) = %v, want %v", a, b, result, a/b)
	}
	fmt.Printf("divide(%.0f, %.0f) = %.1f ✓\n", a, b, result)
}

func main() {
	t := &testing.T{}
	runTest(10, 2, t)
	runTest(20, 4, t)
	fmt.Println("All division tests passed")
}

