package main

import (
	"errors"
	"fmt"
	"testing"
)

func divide(a, b float64) (float64, error) {
	if b == 0 {
		return 0, errors.New("cannot divide by zero")
	}
	return a / b, nil
}

func TestDivide(t *testing.T) {
	tests := []struct {
		a, b    float64
		want    float64
		wantErr bool
	}{
		{10, 2, 5, false},
		{9, 3, 3, false},
		// TODO: add {10, 0, 0, true} — expects an error
	}

	passed := 0
	for _, tt := range tests {
		got, err := divide(tt.a, tt.b)
		if tt.wantErr {
			if err == nil {
				t.Errorf("divide(%v, %v): expected error but got none", tt.a, tt.b)
			} else {
				passed++
			}
		} else {
			if err != nil {
				t.Errorf("divide(%v, %v): unexpected error: %v", tt.a, tt.b, err)
			} else if got != tt.want {
				t.Errorf("divide(%v, %v) = %v, want %v", tt.a, tt.b, got, tt.want)
			} else {
				passed++
			}
		}
	}
	fmt.Printf("%d/%d cases passed\n", passed, len(tests))
}

func main() {
	TestDivide(&testing.T{})
}

