package main

import (
	"fmt"
	"strings"
	"testing"
)

type EmailSender interface {
	Send(to, subject, body string) error
}

type mockSender struct {
	sentTo      string
	sentSubject string
}

func (m *mockSender) Send(to, subject, body string) error {
	m.sentTo = to
	m.sentSubject = subject
	return nil
}

func SendWelcomeEmail(sender EmailSender, userEmail string) {
	sender.Send(userEmail, "Welcome to uByte!", "Thanks for signing up.")
}

func TestSendWelcomeEmail(t *testing.T) {
	mock := &mockSender{}
	SendWelcomeEmail(mock, "alex@example.com")

	if mock.sentTo != "alex@example.com" {
		t.Errorf("sent to %s, want alex@example.com", mock.sentTo)
	}
	if !strings.Contains(mock.sentSubject, "Welcome") {
		t.Errorf("subject %q does not contain Welcome", mock.sentSubject)
	}
	fmt.Println("Email mock test passed")
	fmt.Println("Sent to:", mock.sentTo)
	fmt.Println("Subject:", mock.sentSubject)
}

func main() {
	TestSendWelcomeEmail(&testing.T{})
}

