package main

import (
	"fmt"
	"strings"
	"testing"
)

func buildWithPlus(n int) string {
	s := ""
	for i := 0; i < n; i++ {
		s += "x"
	}
	return s
}

func buildWithBuilder(n int) string {
	var b strings.Builder
	for i := 0; i < n; i++ {
		b.WriteString("x")
	}
	return b.String()
}

func BenchmarkPlus(b *testing.B) {
	for i := 0; i < b.N; i++ {
		buildWithPlus(100)
	}
}

func BenchmarkBuilder(b *testing.B) {
	for i := 0; i < b.N; i++ {
		buildWithBuilder(100)
	}
}

func main() {
	// Run a quick comparison manually
	fmt.Println(len(buildWithPlus(100)), "chars via +")
	fmt.Println(len(buildWithBuilder(100)), "chars via Builder")
}

